import jwt
import datetime
from typing import Optional
from functools import wraps


SECRET_KEY = "your-secret-key-change-in-production"
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 30
REFRESH_TOKEN_EXPIRE_DAYS = 7


def generate_access_token(user_id: int, role: str, extra_claims: Optional[dict] = None) -> str:
    """Generate a JWT access token with user ID and role."""
    payload = {
        "sub": str(user_id),
        "role": role,
        "type": "access",
        "iat": datetime.datetime.utcnow(),
        "exp": datetime.datetime.utcnow() + datetime.timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES),
    }
    if extra_claims:
        payload.update(extra_claims)

    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def generate_refresh_token(user_id: int) -> str:
    """Generate a longer-lived refresh token."""
    payload = {
        "sub": str(user_id),
        "type": "refresh",
        "iat": datetime.datetime.utcnow(),
        "exp": datetime.datetime.utcnow() + datetime.timedelta(days=REFRESH_TOKEN_EXPIRE_DAYS),
    }
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token


def decode_token(token: str) -> dict:
    """Decode and validate a JWT token. Returns the payload if valid."""
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        raise ValueError("Token has expired")
    except jwt.InvalidTokenError as e:
        raise ValueError(f"Invalid token: {e}")


def login(user_id: int, role: str) -> dict:
    """
    Simulate a login: in a real app you'd verify credentials against a database
    first, then generate tokens. After this point, no DB lookup is needed for
    auth — the JWT carries all necessary info.
    """
    access_token = generate_access_token(user_id, role)
    refresh_token = generate_refresh_token(user_id)
    return {
        "access_token": access_token,
        "refresh_token": refresh_token,
        "token_type": "Bearer",
    }


def refresh_access_token(refresh_token: str, role: str) -> dict:
    """Use a refresh token to get a new access token without re-authenticating."""
    payload = decode_token(refresh_token)
    if payload.get("type") != "refresh":
        raise ValueError("Invalid token type: expected refresh token")

    user_id = int(payload["sub"])
    new_access_token = generate_access_token(user_id, role)
    return {
        "access_token": new_access_token,
        "token_type": "Bearer",
    }


def require_auth(f):
    """Decorator that extracts and validates the JWT from a request-like context."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = kwargs.get("token")
        if not token:
            raise PermissionError("Authentication token is required")
        payload = decode_token(token)
        if payload.get("type") != "access":
            raise ValueError("Invalid token type: expected access token")
        kwargs["current_user"] = {
            "user_id": int(payload["sub"]),
            "role": payload["role"],
        }
        return f(*args, **kwargs)
    return decorated


def require_role(*allowed_roles):
    """Decorator that checks if the authenticated user has one of the allowed roles."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            current_user = kwargs.get("current_user")
            if not current_user:
                raise PermissionError("Authentication required before role check")
            if current_user["role"] not in allowed_roles:
                raise PermissionError(
                    f"Role '{current_user['role']}' is not authorized. "
                    f"Required: {allowed_roles}"
                )
            return f(*args, **kwargs)
        return decorated
    return decorator


# --- Example protected endpoints ---

@require_auth
@require_role("admin", "moderator")
def admin_dashboard(token=None, current_user=None):
    return f"Welcome to admin dashboard, user {current_user['user_id']} (role: {current_user['role']})"


@require_auth
def user_profile(token=None, current_user=None):
    return f"Profile for user {current_user['user_id']} (role: {current_user['role']})"


